module traffic_light(
    input rst_n,
    input clk,
    input pass_request,
    output reg red,
    output reg yellow,
    output reg green
); 
//write your code here
// you can modify the module, add your own parameters, wires, reg, etc.
// but do not change the module name and the input and output ports
// declare your parameters here
parameter idle = 2'b00;
parameter s1_red = 2'b01;
parameter s2_yellow = 2'b10;
parameter s3_green = 2'b11;
// declare your wires and reg here
reg [7:0] cnt;
reg [1:0] state;
reg p_red;
reg p_yellow;
reg p_green;
// implement your logic here
always@(*)begin
    case(state)
        idle:begin
            state <= s1_red;
        end
        s1_red:begin
            if(cnt==3) state <= s3_green;
            else state <= s1_red;
        end
        s2_yellow:begin
            if(cnt==3) state <= s1_red;
            else state <= s2_yellow;
        end
        s3_green:begin
            if(cnt==3) state <= s2_yellow;
            else state <= s3_green;
        end
        default:begin
            state <= idle;
        end
    endcase
end
always@(posedge clk or negedge rst_n)begin
    if(!rst_n)cnt<=10;
    else begin
        if(pass_request&&green)cnt<=10;
        else if(!green&&p_green)cnt<=60;
        else if(!yellow&&p_yellow)cnt<=5;
        else if(!red&&p_red)cnt<=10;
        else cnt<=cnt-1;
    end
end
always@(*)begin
    clock = cnt;
end
always@(posedge clk or negedge rst_n)begin
    if(!rst_n)begin
        red <= 0;
        yellow <= 0;
        green <= 0;
    end
    else begin
        red <= p_red;
        yellow <= p_yellow;
        green <= p_green;
    end
end
always@(*)begin
    case(state)
        idle:begin
            p_red = 0;
            p_yellow = 0;
            p_green = 0;
        end
        s1_red:begin
            p_red = 1;
            p_yellow = 0;
            p_green = 0;
        end
        s2_yellow:begin
            p_red = 0;
            p_yellow = 1;
            p_green = 0;
        end
        s3_green:begin
            p_red = 0;
            p_yellow = 0;
            p_green = 1;
        end
        default:begin
            p_red = 0;
            p_yellow = 0;
            p_green = 0;
        end
    endcase
end
endmodule
